I'm not loving the ergonomics of the `MISCONFIGURATION` error. 

```ts web/breeze/components/CalcPage/hooks/useLocalPackageSelection.ts
import { useReducer } from 'react';
import {
  getFinancingOption,
  isBatteryPackage,
  isEvChargerPackage,
  isPackageUpgraded,
} from '../../../lib/packageUtils';
import {
  MisconfigurationError,
  PackageChange,
  PackageStatePV,
} from '../../../stores/Interest/type';
import { Cloud$PurchaseModelCode } from '@otovo/shared/types/cloudEnums';
import {
  Cloud$FinancingOption,
  Cloud$Interest,
  Cloud$Package,
  Cloud$PackageVariantPV,
  Cloud$Product,
} from '@otovo/shared/types/cloudApi';

type LocalState = {
  selectedPackage: Cloud$Package;
  previousPackage: Cloud$Package | null;
  selectedFinancingOption: Cloud$FinancingOption;
  error: PackageStatePV['error'];
};

type LocalAction =
  | { type: 'CHANGE_PACKAGE'; package: Cloud$Package }
  | { type: 'CHANGE_PURCHASE_MODEL'; code: Cloud$PurchaseModelCode }
  | { type: 'SET_ERROR'; error: PackageStatePV['error'] };

function localReducer(state: LocalState, action: LocalAction): LocalState {
  switch (action.type) {
    case 'CHANGE_PACKAGE':
      return {
        ...state,
        previousPackage: state.selectedPackage,
        selectedPackage: action.package,
        selectedFinancingOption: action.package.price.financing_options[0],
        error: null,
      };
    case 'CHANGE_PURCHASE_MODEL': {
      const newFinancingOption = getFinancingOption(
        state.selectedPackage.price.financing_options,
        action.code,
      );

      if (!newFinancingOption) {
        // TODO: Consider handling this?
        return { ...state, error: null };
      }

      return {
        ...state,
        selectedFinancingOption: newFinancingOption,
      };
    }
    case 'SET_ERROR':
      return {
        ...state,
        error: action.error,
      };
    default:
      return action;
  }
}

function createVariantFromPackage(pkg: Cloud$Package): Cloud$PackageVariantPV {
  return {
    main_hardware_type: 'pv_system',
    product_name: pkg.product_name, // Pointer back to the product (e.g. standard)
    pv_package_size: pkg.package_size, // e.g. small, medium, large
    name: pkg.name, // e.g. combination of the two above: standard_small
    with_battery: isBatteryPackage(pkg),
    with_ev_charger: isEvChargerPackage(pkg),
    number_of_panels: pkg.price.num_panels,
    nominal_system_power: pkg.price.nominal_system_power,
    nominal_panel_power: pkg.price.equipment.panels.nominal_panel_power,
  };
}

function getAvailablePackageVariants(
  products: Cloud$Product[],
): Cloud$PackageVariantPV[] {
  return products.flatMap((p) => p.packages).map(createVariantFromPackage);
}

function getInitialState(interest: Cloud$Interest): LocalState {
  const activePackage = interest.active_shopping_cart_package;

  if (!activePackage) {
    throw new Error('No active package found for PV system');
  }

  // Default to the first financing option if none is specified in the interest
  const defaultFinancingOption = getFinancingOption(
    activePackage.price.financing_options,
    interest.default_purchase_model,
  );

  if (!defaultFinancingOption) {
    throw new Error('No financing options available for package');
  }

  return {
    selectedPackage: activePackage,
    previousPackage: null,
    selectedFinancingOption: defaultFinancingOption,
    error: null,
  };
}

export function useLocalPackageSelection(
  interest: Cloud$Interest,
  additionalProducts?: Cloud$Product[],
): PackageStatePV {
  const [state, dispatch] = useReducer(localReducer, interest, getInitialState);

  const allProducts = interest.products;
  const allVariants = getAvailablePackageVariants(allProducts);

  const productNames = new Set(allVariants.map((p) => p.product_name));

  // Add any new products that we don't already have in the initial interest response
  if (additionalProducts?.length) {
    additionalProducts
      .filter((p) => !productNames.has(p.name))
      .forEach((p) => allProducts.push(p));
  }

  const changePackage: PackageStatePV['changePackage'] = async (pkgChange) => {
    const currentVariant = createVariantFromPackage(state.selectedPackage);
    const changedVariant = {
      ...currentVariant,
      [pkgChange.option]: pkgChange.value,
    };

    const newPackage = interest.products
      .flatMap((p) => p.packages)
      .find(
        (p) =>
          p.product_name === changedVariant.product_name &&
          p.package_size === changedVariant.pv_package_size &&
          isBatteryPackage(p) === changedVariant.with_battery &&
          isEvChargerPackage(p) === changedVariant.with_ev_charger,
      );

    if (process.env.NODE_ENV === 'development') {
      const { group, groupEnd, debug } = console;
      group('Package Selection');
      debug('Package Change:', pkgChange);
      debug('Variant Change \nfrom:', currentVariant, '\nto:', changedVariant);
      debug('Available Products:', interest.products);
      debug(
        'Package changed \nfrom:',
        state.selectedPackage,
        '\nto:',
        newPackage,
      );
      groupEnd();
    }

    if (!newPackage) {
      const currentConfig: PackageChange[] = [
        { option: 'product_name', value: currentVariant.product_name },
      ];
      if (currentVariant.with_battery) {
        currentConfig.push({
          option: 'with_battery',
          value: true,
        });
      }
      if (currentVariant.with_ev_charger) {
        currentConfig.push({
          option: 'with_ev_charger',
          value: true,
        });
      }
      dispatch({
        type: 'SET_ERROR',
        error: {
          type: 'MISCONFIGURATION',
          details: {
            attemptedChange: pkgChange,
            currentConfig: currentConfig,
          },
        },
      });
      return;
    }

    dispatch({ type: 'CHANGE_PACKAGE', package: newPackage });
  };

  const changePurchaseModel = (code: Cloud$PurchaseModelCode) => {
    dispatch({ type: 'CHANGE_PURCHASE_MODEL', code });
  };

  return {
    selectedPackage: state.selectedPackage,
    selectedFinancingOption: state.selectedFinancingOption,
    availablePackages: allVariants,
    isLoading: false, // Local selection is always synchronous
    isMutating: false,
    isPackageUpgraded: state.previousPackage && isPackageUpgraded(state),
    mainHardwareType: 'pv_system',
    changePackage,
    changePurchaseModel,
    error: state.error,
  };
}
```


