You're right - the reuse of `PackageChange` for the current configuration feels like a bit of a hack just to reuse the translation logic. Here's how we could make it clearer:

```typescript
// First, let's define what we're actually representing - the active features/selections
type ActivePackageFeature =
  | { type: 'panel_type'; name: Cloud$ProductName }
  | { type: 'battery' }
  | { type: 'ev_charger' };

// The function name could be getActiveFeatures or getPackageFeatures
export function getActiveFeatures(variant: Cloud$PackageVariantPV): ActivePackageFeature[] {
  const features: ActivePackageFeature[] = [
    { type: 'panel_type', name: variant.product_name },
  ];

  if (variant.with_battery) {
    features.push({ type: 'battery' });
  }

  if (variant.with_ev_charger) {
    features.push({ type: 'ev_charger' });
  }

  return features;
}

// Then we could update the translation function to handle both cases
function getMessageForFeature(
  feature: ActivePackageFeature | PackageChange
): MessageDescriptor {
  if ('option' in feature) {
    // Handle PackageChange case
    switch (feature.option) {
      case 'with_battery':
        return sharedMessages.wordBattery;
      case 'with_ev_charger':
        return sharedMessages.wordEvCharger;
      case 'product_name':
        return getPanelTypeWithPanelsWordMessage(feature.value);
      default:
        return null;
    }
  } else {
    // Handle ActivePackageFeature case
    switch (feature.type) {
      case 'battery':
        return sharedMessages.wordBattery;
      case 'ev_charger':
        return sharedMessages.wordEvCharger;
      case 'panel_type':
        return getPanelTypeWithPanelsWordMessage(feature.name);
    }
  }
}

// Update the error type
type MisconfigurationError = {
  type: 'MISCONFIGURATION';
  attemptedChange: PackageChange;
  activeFeatures: ActivePackageFeature[];
};

// Update the toast props
type Props = {
  attemptedChange: PackageChange;
  activeFeatures: ActivePackageFeature[];
  id: string;
};
```

This makes the code more honest about what it's actually representing - the current active features of a package, rather than trying to shoe-horn it into the `PackageChange` structure. The translation function can handle both types, but each type now better represents its actual purpose:

- `PackageChange` represents a requested change to the package
- `ActivePackageFeature` represents a current feature of the package

We could even take it further and rename things to make the distinction even clearer:
- `attemptedChange` → `requestedFeature`
- `activeFeatures` → `currentFeatures`

This better reflects that we're trying to add a new feature to an existing set of features.




