import { useCallback } from 'react';
import {
  PackageChange,
  PackageChangeBattery,
} from '../../../stores/Interest/type';
import { logChoiceSelection } from '../utils/logging';
import {
  Cloud$MainHardwareType,
  Cloud$PackageSize,
  Cloud$ProductName,
} from '@otovo/shared/types/cloudEnums';

const optionToLabel = {
  product_name: 'product',
  package_size: 'package',
  battery_package_size: 'package',
  with_battery: 'battery',
} as const;

type CalcPageActions<T extends PackageChange | PackageChangeBattery> = {
  changePvProductName: T extends PackageChange
    ? (value: Cloud$ProductName) => void
    : never;
  changePvPackageSize: T extends PackageChange
    ? (value: Cloud$PackageSize) => void
    : never;
  changeBatteryPackageSize: T extends PackageChangeBattery
    ? (value: Cloud$PackageSize) => void
    : never;
  toggleBattery: T extends PackageChange ? (value: boolean) => void : never;
  toggleEvCharger: (
    mainHardwareType: Cloud$MainHardwareType,
    value: boolean,
  ) => void;
};

function useCalcPageActions<T extends PackageChange | PackageChangeBattery>(
  onPackageChange: (change: T) => Promise<void>,
  experimentVersion: string,
): CalcPageActions<T> {
  const changePackage = useCallback(
    (packageChange: T) => {
      if (packageChange.option !== 'with_ev_charger') {
        const label = optionToLabel[packageChange.option];
        logChoiceSelection({
          choiceLabel: label,
          changedTo: String(packageChange.value),
          experimentVersion,
        });
      }
      onPackageChange(packageChange);
    },
    [onPackageChange, experimentVersion],
  );

  const shortcuts = {
    changePvProductName: ((value: Cloud$ProductName) =>
      changePackage({ option: 'product_name', value } as T)) as any,
    changePvPackageSize: ((value: Cloud$PackageSize) =>
      changePackage({ option: 'pv_package_size', value } as T)) as any,
    changeBatteryPackageSize: ((value: Cloud$PackageSize) =>
      changePackage({ option: 'battery_package_size', value } as T)) as any,
    toggleBattery: ((value: boolean) =>
      changePackage({ option: 'with_battery', value } as T)) as any,
    toggleEvCharger: (
      mainHardwareType: Cloud$MainHardwareType,
      value: boolean,
    ) => {
      changePackage({
        option: 'with_ev_charger',
        value,
      } as T);

      logChoiceSelection({
        choiceLabel: 'evCharger',
        changedTo: String(value),
        experimentVersion,
        mainHardwareType: mainHardwareType,
      });
    },
  };

  return shortcuts;
}

export default useCalcPageActions;
